import json
with open('/Users/zaihuilou/.openclaw/openclaw.json', 'r') as f:
    cfg = json.load(f)

# 找所有包含 feishu_drive_file 的白名单列表，把 feishu_drive_permission 加进去
def add_permission(obj):
    if isinstance(obj, list):
        if 'feishu_drive_file' in obj and 'feishu_drive_permission' not in obj:
            obj.append('feishu_drive_permission')
            obj.sort()
        for item in obj:
            add_permission(item)
    elif isinstance(obj, dict):
        for v in obj.values():
            add_permission(v)

add_permission(cfg)

with open('/Users/zaihuilou/.openclaw/openclaw.json', 'w') as f:
    json.dump(cfg, f, indent=2, ensure_ascii=False)
print('done')
"

